-- Import staff data extracted from Nursing License & CPD Tracking Sheet.xlsx
-- Safe to run more than once: it updates existing rows by username.
alter table staff_cpd add column if not exists category1_points numeric default 0;
alter table staff_cpd add column if not exists category23_points numeric default 0;

create unique index if not exists staff_cpd_username_unique on staff_cpd(username);

on conflict (username) do update set
  password=excluded.password,
  role=excluded.role,
  active=excluded.active,
  full_name=excluded.full_name,
  department=excluded.department,
  area=excluded.area,
  assigned_doctor=excluded.assigned_doctor,
  joining_date=excluded.joining_date,
  dhp_license=excluded.dhp_license,
  qid=excluded.qid,
  dhp_expiry=excluded.dhp_expiry,
  category1_points=excluded.category1_points,
  category23_points=excluded.category23_points,
  email=excluded.email,
  mobile=excluded.mobile,
  notes=excluded.notes,
  updated_at=now();
